1	import fs from "node:fs";
2	import path from "node:path";
3	import type { Metadata } from "next";
4	import Link from "next/link";
5	
6	import PublicHeader from "@/components/PublicHeader";
7	import { getFounder } from "@/lib/auth";
8	
9	export const metadata: Metadata = {
10	  title: "Methodology · Quintin Hypothesis Benchmark",
11	  description:
12	    "A frozen, public, replicable benchmark for the Quintin Hypothesis: that logical coherence is a geometric property of embedding space. Includes a leaderboard the firm itself can lose on.",
13	  openGraph: {
14	    title: "Quintin Hypothesis Benchmark",
15	    description:
16	      "Benchmark dataset, harness, and leaderboard for the Quintin Hypothesis.",
17	    type: "website",
18	  },
19	};
20	
21	export const dynamic = "force-dynamic";
22	
23	const RUNNERS = ["random", "cosine", "contradiction_geometry"] as const;
24	type Runner = (typeof RUNNERS)[number];
25	
26	type DomainMetrics = {
27	  n: number;
28	  accuracy: number;
29	  auroc_contradicting_vs_coherent: number;
30	};
31	
32	type Metrics = {
33	  n: number;
34	  accuracy: number;
35	  auroc_contradicting_vs_coherent: number;
36	  ece_contradicting: number;
37	  latency_ms_p50: number;
38	  latency_ms_p95: number;
39	  by_domain: Record<string, DomainMetrics>;
40	  confusion: Record<string, Record<string, number>>;
41	  label_distribution: Record<string, number>;
42	  predicted_distribution: Record<string, number>;
43	};
44	
45	type MetricsPayload = {
46	  benchmark_version: string;
47	  runner: string;
48	  embedder: string;
49	  git_sha: string;
50	  timestamp_utc: string;
51	  n_items: number;
52	  seed: number;
53	  metrics: Metrics;
54	};
55	
56	function readMetrics(runner: Runner): MetricsPayload | null {
57	  const candidates = [
58	    path.join(process.cwd(), "public", "qh-benchmark", `metrics_${runner}.json`),
59	    path.join(
60	      process.cwd(),
61	      "..",
62	      "benchmarks",
63	      "quintin_hypothesis",
64	      "v1",
65	      "results",
66	      `metrics_${runner}.json`,
67	    ),
68	  ];
69	  for (const p of candidates) {
70	    try {
71	      const text = fs.readFileSync(p, "utf8");
72	      return JSON.parse(text) as MetricsPayload;
73	    } catch {
74	      // try next
75	    }
76	  }
77	  return null;
78	}
79	
80	function fmt(n: number, digits = 4): string {
81	  if (!Number.isFinite(n)) return "n/a";
82	  return n.toFixed(digits);
83	}
84	
85	function asPercent(n: number): string {
86	  if (!Number.isFinite(n)) return "n/a";
87	  return (n * 100).toFixed(2) + "%";
88	}
89	
90	function bestRunnerOnSlice(
91	  payloads: Record<Runner, MetricsPayload | null>,
92	  metric: "accuracy" | "auroc_contradicting_vs_coherent",
93	  domain: string | null,
94	): Runner | null {
95	  let best: Runner | null = null;
96	  let bestVal = -Infinity;
97	  for (const r of RUNNERS) {
98	    const m = payloads[r]?.metrics;
99	    if (!m) continue;
100	    const val =
101	      domain === null
102	        ? m[metric]
103	        : (m.by_domain?.[domain]?.[metric] ?? -Infinity);
104	    if (Number.isFinite(val) && val > bestVal) {
105	      bestVal = val;
106	      best = r;
107	    }
108	  }
109	  return best;
110	}
111	
112	export default async function QHBenchmarkPage() {
113	  const founder = await getFounder();
114	  const payloads: Record<Runner, MetricsPayload | null> = {
115	    random: readMetrics("random"),
116	    cosine: readMetrics("cosine"),
117	    contradiction_geometry: readMetrics("contradiction_geometry"),
118	  };
119	
120	  const anyPayload =
121	    payloads.contradiction_geometry ?? payloads.cosine ?? payloads.random;
122	
123	  const domainList: string[] = anyPayload
124	    ? Object.keys(anyPayload.metrics.by_domain).sort()
125	    : [];
126	
127	  const bestOverallAcc = bestRunnerOnSlice(payloads, "accuracy", null);
128	  const bestOverallAuroc = bestRunnerOnSlice(
129	    payloads,
130	    "auroc_contradicting_vs_coherent",
131	    null,
132	  );
133	
134	  return (
135	    <>
136	      <PublicHeader authed={Boolean(founder)} />
137	      <main className="qh-page">
138	        <header className="qh-hero">
139	          <p className="qh-eyebrow">
140	            <Link href="/methodology">Methodology</Link>
141	            <span aria-hidden> · </span>
142	            <span>Benchmark</span>
143	          </p>
144	          <h1>Quintin Hypothesis Benchmark</h1>
145	          <p className="qh-lede">
146	            <strong>The hypothesis is empirical or it is not.</strong> The
147	            firm has chosen empirical. This page is the leaderboard the
148	            firm itself can lose on. If a one-line cosine baseline beats
149	            the firm's contradiction-geometry probe on a slice, that is
150	            shown here in plain sight.
151	          </p>
152	          <p className="qh-lede">
153	            The Quintin Hypothesis predicts that the difference vector
154	            between embeddings of a premise and its logical contradiction
155	            is <em>sparse</em> (concentrated in few dimensions, per Hoyer
156	            sparsity), while the difference between a premise and a
157	            coherent continuation is dense. The benchmark tests this
158	            prediction against {anyPayload?.n_items ?? "—"} frozen items
159	            spanning physics, economics, and ethics.
160	          </p>
161	        </header>
162	
163	        {!anyPayload && (
164	          <section className="qh-empty">
165	            <h2>No results yet</h2>
166	            <p>
167	              The benchmark harness has not produced a results file in
168	              this checkout. Run{" "}
169	              <code>noosphere benchmark qh --runner contradiction_geometry</code>{" "}
170	              to populate this page, or wait for the nightly CI job.
171	            </p>
172	          </section>
173	        )}
174	
175	        {anyPayload && (
176	          <section className="qh-section">
177	            <h2>Leaderboard</h2>
178	            <p className="qh-meta">
179	              Benchmark version <code>{anyPayload.benchmark_version}</code> ·
180	              embedder <code>{anyPayload.embedder}</code> · git SHA{" "}
181	              <code>{anyPayload.git_sha?.slice(0, 8) || "unknown"}</code> ·
182	              run at <code>{anyPayload.timestamp_utc}</code>.
183	            </p>
184	            <table className="qh-table">
185	              <thead>
186	                <tr>
187	                  <th scope="col">Runner</th>
188	                  <th scope="col">n</th>
189	                  <th scope="col">Accuracy (3-way)</th>
190	                  <th scope="col">AUROC (contradicting vs coherent)</th>
191	                  <th scope="col">ECE</th>
192	                  <th scope="col">Latency p50 (ms)</th>
193	                </tr>
194	              </thead>
195	              <tbody>
196	                {RUNNERS.map((r) => {
197	                  const p = payloads[r];
198	                  if (!p) {
199	                    return (
200	                      <tr key={r}>
201	                        <th scope="row">{r}</th>
